    // Cached width based on line count
    float computed_width_ = GutterConfig::MIN_WIDTH;

    // Layout cache for line number text (avoids per-frame TextLayout creation)
    LineNumberLayoutCache layout_cache_;

    // ========================================================================
    // Constructor / Destructor
    // ========================================================================

    GutterWidget();
    ~GutterWidget();

